use serde::{Deserialize, Serialize};

/// Macro to create an enum with forward-compatible `Other(String)` variant.
/// Generates the enum definition, Serialize, and custom Deserialize.
#[macro_export]
macro_rules! openai_enum {
    (
        $(#[$meta:meta])*
        $vis:vis enum $name:ident {
            $(
                $(#[$variant_meta:meta])*
                $variant:ident$(($variant_inner:ty))?
            ),*$(,)?
        }
        snake_case: $($snake:ident => $snake_variant:ident),*$(,)?
    ) => {
        $(#[$meta])*
        #[derive(Debug, Clone, PartialEq, Eq, Serialize)]
        #[non_exhaustive]
        $vis enum $name {
            $(
                $(#[$variant_meta])*
                $variant$(($variant_inner))?,
            )*
            /// Catch-all for unknown variants (forward compatibility).
            #[serde(serialize_with = "serialize_other")]
            Other(String),
        }

        impl<'de> Deserialize<'de> for $name {
            fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
            where
                D: serde::Deserializer<'de>,
            {
                let s = String::deserialize(deserializer)?;
                match s.as_str() {
                    $(stringify!($snake) => Ok($name::$snake_variant),)*
                    _ => Ok($name::Other(s)),
                }
            }
        }
    };
}

fn serialize_other<S>(value: &String, serializer: S) -> Result<S::Ok, S::Error>
where
    S: serde::Serializer,
{
    serializer.serialize_str(value)
}

openai_enum! {
    /// Message role in chat/thread conversations.
    pub enum Role {
        System,
        Developer,
        User,
        Assistant,
        Tool,
        Function,
    }
    snake_case:
        system => System,
        developer => Developer,
        user => User,
        assistant => Assistant,
        tool => Tool,
        function => Function,
}

/// Token usage information returned by the API.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Usage {
    pub prompt_tokens: Option<i64>,
    pub completion_tokens: Option<i64>,
    pub total_tokens: Option<i64>,
    /// Detailed breakdown of prompt tokens.
    #[serde(default)]
    pub prompt_tokens_details: Option<PromptTokensDetails>,
    /// Detailed breakdown of completion tokens.
    #[serde(default)]
    pub completion_tokens_details: Option<CompletionTokensDetails>,
}

/// Detailed breakdown of prompt token usage.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PromptTokensDetails {
    #[serde(default)]
    pub cached_tokens: Option<i64>,
    #[serde(default)]
    pub audio_tokens: Option<i64>,
}

openai_enum! {
    /// Reason the model stopped generating tokens.
    pub enum FinishReason {
        Stop,
        Length,
        ToolCalls,
        ContentFilter,
        FunctionCall,
    }
    snake_case:
        stop => Stop,
        length => Length,
        tool_calls => ToolCalls,
        content_filter => ContentFilter,
        function_call => FunctionCall,
}

impl std::fmt::Display for FinishReason {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::Stop => write!(f, "stop"),
            Self::Length => write!(f, "length"),
            Self::ToolCalls => write!(f, "tool_calls"),
            Self::ContentFilter => write!(f, "content_filter"),
            Self::FunctionCall => write!(f, "function_call"),
            Self::Other(s) => write!(f, "{}", s),
        }
    }
}

