pub mod serde_snake_case_other {
    use serde::{Deserialize, Deserializer, Serialize, Serializer};

    pub fn serialize<T, S>(value: &T, serializer: S) -> Result<S::Ok, S::Error>
    where
        T: AsSnakeCaseStr,
        S: Serializer,
    {
        serializer.serialize_str(value.as_snake_case_str())
    }

    pub fn deserialize<'de, T, D>(deserializer: D) -> Result<T, D::Error>
    where
        T: FromSnakeCaseStr,
        D: Deserializer<'de>,
    {
        let s = String::deserialize(deserializer)?;
        T::from_snake_case_str(&s)
            .ok_or_else(|| serde::de::Error::custom("unknown variant"))
    }
}

pub trait AsSnakeCaseStr {
    fn as_snake_case_str(&self) -> &str;
}

pub trait FromSnakeCaseStr: Sized {
    fn from_snake_case_str(s: &str) -> Option<Self>;
}
```

