impl FromSnakeCaseStr for Role {
    fn from_snake_case_str(s: &str) -> Option<Self> {
        match s {
            "system" => Some(Role::System),
            "user" => Some(Role::User),
            _ => Some(Role::Other(s.to_string())),
        }
    }
}
```

