pub struct Image {
    /// The URL of the generated image (if response_format is url).
    #[serde(default)]
    pub url: Option<String>,
    /// The base64-encoded JSON of the generated image (if response_format is b64_json).
    #[serde(default)]
    pub b64_json: Option<String>,
    /// The prompt that was used to generate the image (dall-e-3 only).
    #[serde(default)]
    pub revised_prompt: Option<String>,
}

impl Image {
    /// Decode the base64 image data and save it to a file.
    #[cfg(feature = "images")]
    pub fn save(&self, path: &std::path::Path) -> Result<(), crate::error::OpenAIError> {
        use std::io::Write;

        let b64 = self
            .b64_json
            .as_ref()
            .ok_or_else(|| crate::error::OpenAIError::InvalidRequest {
                message: "No base64 data available".into(),
            })?;
        let bytes = base64::Engine::decode(
            &base64::engine::general_purpose::STANDARD,
            b64,
        )
        .map_err(|e| crate::error::OpenAIError::InvalidRequest {
            message: format!("Failed to decode base64: {}", e),
        })?;
        let mut file = std::fs::File::create(path).map_err(|e| {
            crate::error::OpenAIError::InvalidRequest {
                message: format!("Failed to create file: {}", e),
            }
        })?;
        file.write_all(&bytes).map_err(|e| {
            crate::error::OpenAIError::InvalidRequest {
                message: format!("Failed to write file: {}", e),
            }
        })?;
        Ok(())
