        use std::io::Write;

        let b64 = self
            .b64_json
            .as_ref()
            .ok_or_else(|| crate::error::OpenAIError::InvalidArgument("No base64 data available".into()))?;
        let bytes = base64::Engine::decode(
            &base64::engine::general_purpose::STANDARD,
            b64,
